#include <stdio.h>
#include <string.h>

int main() {
    char i[6], f[6];
    scanf("%s", i);
    scanf("%s", f);
    int ti = ((i[0] - '0') * 10 + (i[1] - '0')) * 60 + (i[3] - '0') * 10 + (i[4] - '0');
    int tf = ((f[0] - '0') * 10 + (f[1] - '0')) * 60 + (f[3] - '0') * 10 + (f[4] - '0');
    float m = (ti + tf) / 2.0;
    float tm = ti + (tf - m);
    int hours = (int)(tm / 60);
    int minutes = (int)tm % 60;
    if (hours >= 10 && minutes >= 10) {
        printf("%d:%d", hours, minutes);
    } else if (hours >= 10 && minutes < 10) {
        printf("%d:0%d", hours, minutes);
    } else if (hours < 10 && minutes >= 10) {
        printf("0%d:%d", hours, minutes);
    } else {
        printf("0%d:0%d", hours, minutes);
    }
    return 0;
}
